121	func isFullCommitSHA(commitSHA string) bool {
122		if len(commitSHA) != 40 {
123			return false
124		}
125		for i := 0; i < len(commitSHA); i++ {
126			c := commitSHA[i]
127			if c >= '0' && c <= '9' {
128				continue
129			}
130			if c >= 'a' && c <= 'f' {
131				continue
132			}
133			if c >= 'A' && c <= 'F' {
134				continue
135			}
136			return false
137		}
138		return true
139	}
