141	func (f *CommandFactory) resolveClosingCommitSHA(commitSHA string) (string, error) {
142		normalizedCommitSHA, err := f.resolveCommitSHA(commitSHA)
143		if err != nil {
144			return "", fmt.Errorf("invalid closing_commit_sha %q: %w", commitSHA, err)
145		}
146		if normalizedCommitSHA == "" {
147			return "", fmt.Errorf("invalid closing_commit_sha %q: empty value", commitSHA)
148		}
149		return normalizedCommitSHA, nil
150	}
