152	// commitIsMetadataOnlyTrackerBackfill reports whether the given commit changed
153	// only bead tracker state. Closing provenance is suppressed only for pure
154	// tracker backfills that touch .ddx/beads.jsonl and nothing else.
155	func (f *CommandFactory) commitIsMetadataOnlyTrackerBackfill(commitSHA string) bool {
156		if commitSHA == "" {
157			return false
158		}
159	
160		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
161		defer cancel()
162	
163		cmd := gitpkg.Command(ctx, f.WorkingDir, "show", "--pretty=format:", "--name-only", commitSHA)
164		out, err := cmd.Output()
165		if err != nil {
166			return false
167		}
168	
169		for _, line := range strings.Split(string(out), "\n") {
170			path := strings.TrimSpace(line)
171			if path == "" {
172				continue
173			}
174			if path != ".ddx/beads.jsonl" {
175				return false
176			}
177		}
178	
179		return true
180	}
181	
182	func isReviewCloseBead(b *bead.Bead) bool {
183		if b == nil {
184			return false
185		}
186		for _, label := range b.Labels {
187			switch label {
188			case "action:review", "kind:review", "phase:review", "review-finding":
189				return true
190			}
191		}
192		return false
193	}
