195	func (f *CommandFactory) beadWorkspaceRoot() string {
196		dir := os.Getenv("DDX_BEAD_DIR")
197		if dir != "" {
198			if filepath.Base(dir) == ".ddx" {
199				return filepath.Dir(dir)
200			}
201			return dir
202		}
203		if f.WorkingDir == "" {
204			return ""
205		}
206		if workspaceRoot := gitpkg.FindNearestDDxWorkspace(f.WorkingDir); workspaceRoot != "" {
207			return workspaceRoot
208		}
209		return f.WorkingDir
210	}
211	
212	func (f *CommandFactory) beadStore() *bead.Store {
213		workspaceRoot := f.beadWorkspaceRoot()
214		if workspaceRoot == "" {
215			return bead.NewStore("")
216		}
217		return bead.NewStore(filepath.Join(workspaceRoot, ".ddx"))
218	}
