220	func (f *CommandFactory) newBeadInitCommand() *cobra.Command {
221		return &cobra.Command{
222			Use:   "init",
223			Short: "Initialize bead storage",
224			Args:  cobra.NoArgs,
225			RunE: func(cmd *cobra.Command, args []string) error {
226				s := f.beadStore()
227				if err := s.Init(); err != nil {
228					return err
229				}
230				fmt.Fprintf(cmd.OutOrStdout(), "Initialized bead storage at %s\n", s.File)
231	
232				// Auto-migrate from .helix/issues.jsonl if present
233				n, migrated, err := s.MigrateFromHelix()
234				if err != nil {
235					fmt.Fprintf(cmd.ErrOrStderr(), "Warning: migration from .helix/issues.jsonl failed: %v\n", err)
236				} else if migrated {
237					fmt.Fprintf(cmd.OutOrStdout(), "Migrated %d beads from .helix/issues.jsonl\n", n)
238				}
239				return nil
240			},
241		}
242	}
