244	func (f *CommandFactory) newBeadCreateCommand() *cobra.Command {
245		cmd := &cobra.Command{
246			Use:   "create <title>",
247			Short: "Create a new bead",
248			Args:  cobra.ExactArgs(1),
249			RunE: func(cmd *cobra.Command, args []string) error {
250				s := f.beadStore()
251				b := &bead.Bead{Title: args[0]}
252	
253				if v, _ := cmd.Flags().GetString("type"); v != "" {
254					b.IssueType = v
255				}
256				if v, _ := cmd.Flags().GetInt("priority"); cmd.Flags().Changed("priority") {
257					b.Priority = v
258				}
259				if v, _ := cmd.Flags().GetString("labels"); v != "" {
260					b.Labels = strings.Split(v, ",")
261				}
262				if v, _ := cmd.Flags().GetString("acceptance"); v != "" {
263					b.Acceptance = v
264				}
265				if v, _ := cmd.Flags().GetString("description"); v != "" {
266					b.Description = v
267				}
268				if v, _ := cmd.Flags().GetString("parent"); v != "" {
269					b.Parent = v
270				}
271				if setFlags, _ := cmd.Flags().GetStringArray("set"); len(setFlags) > 0 {
272					if b.Extra == nil {
273						b.Extra = make(map[string]any)
274					}
275					for _, kv := range setFlags {
276						k, v, ok := strings.Cut(kv, "=")
277						if !ok {
278							return fmt.Errorf("--set requires key=value format, got: %s", kv)
279						}
280						switch v {
281						case "true":
282							b.Extra[k] = true
283						case "false":
284							b.Extra[k] = false
285						default:
286							b.Extra[k] = v
287						}
288					}
289				}
290	
291				if err := s.Create(b); err != nil {
292					return err
