1558		}
1559	
1560		if rootID != "" {
1561			target, ok := byID[rootID]
1562			if !ok {
1563				return "", fmt.Errorf("bead: not found: %s", rootID)
1564			}
1565			var sb strings.Builder
1566			// Walk up: show the dependency chain (what this node depends on)
1567			depChain := s.depChainUp(byID, rootID)
1568			if len(depChain) > 0 {
1569				// Print deps as the tree root(s), with the target as their child
1570				for _, depID := range depChain {
1571					if dep, ok := byID[depID]; ok {
1572						fmt.Fprintf(&sb, "%s [%s] %s\n", dep.ID, dep.Status, dep.Title)
1573					}
1574				}
1575			}
1576			// Print the target node
1577			fmt.Fprintf(&sb, "%s [%s] %s\n", target.ID, target.Status, target.Title)
1578			// Print dependents (what depends on this node)
1579			var children []string
1580			for _, other := range sortedKeys(byID) {
1581				if byID[other].HasDep(rootID) {
1582					children = append(children, other)
1583				}
1584			}
1585			for _, child := range children {
1586				s.printTree(&sb, byID, child, "  ", true)
1587			}
1588			return sb.String(), nil
1589		}
1590	
1591		// Find roots (beads that have no dependencies themselves)
1592		var roots []string
1593		for _, b := range beads {
1594			if len(b.Dependencies) == 0 {
1595				roots = append(roots, b.ID)
1596			}
1597		}
1598		sort.Strings(roots)
1599	
1600		var sb strings.Builder
1601		for i, root := range roots {
