1617		if prefix == "" {
1618			connector = ""
1619		}
1620	
1621		fmt.Fprintf(sb, "%s%s%s [%s] %s\n", prefix, connector, b.ID, b.Status, b.Title)
1622	
1623		// Find beads that depend on this one (children in the tree)
1624		var children []string
1625		for _, other := range sortedKeys(byID) {
